import React, { useState, useEffect, useRef } from 'react';
import api from '../api/axiosConfig';
import ReactMarkdown from 'react-markdown';
import { Terminal, Cpu, Download, ShieldCheck, Zap, BarChart3, Activity, AlertTriangle } from 'lucide-react';
import toast from 'react-hot-toast';

const INPUT_BG = '#111318';

const GeneratePage = () => {
  const [query, setQuery]     = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult]   = useState(null);
  const [visible, setVisible] = useState(false);
  const resultRef = useRef(null);

  // Auto-scroll to results
  useEffect(() => {
    if (visible && resultRef.current) {
      resultRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [visible]);

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!query.trim()) return;
    setLoading(true);
    setResult(null);
    setVisible(false);
    try {
      // Matches the backend /portfolio/generate route exactly
      const response = await api.post('/portfolio/generate', { query });
      setResult(response.data.data);
      requestAnimationFrame(() => setVisible(true));
      toast.success('STRATEGY_SYNTHESIS_COMPLETE');
    } catch (err) {
      console.error('Synthesis Node Failure:', err);
      toast.error('SYSTEM_FAILURE: AGENTIC_DEBATE_INTERRUPTED');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadPDF = async () => {
    try {
      // Ensure your backend has a route at /portfolio/export that takes this data
      const response = await api.post('/portfolio/export', result, { responseType: 'blob' });
      const url  = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href  = url;
      link.setAttribute('download', `Finify_Strategy_${Date.now()}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch {
      toast.error('PDF_EXPORT_FAILED');
    }
  };

  return (
    <div
      className="reveal-node"
      style={{
        flex: 1,
        width: '100%',
        maxWidth: '1200px',
        margin: '0 auto',
        padding: '2.5rem 1.5rem',
        boxSizing: 'border-box',
        display: 'flex',
        flexDirection: 'column',
        gap: '2rem',
      }}
    >
      {/* ── Header ── */}
      <div style={{ paddingBottom: '1.5rem', borderBottom: '1px solid var(--surface-border)' }}>
        <h1 style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '1.4rem', fontWeight: 800, letterSpacing: '-0.02em', textTransform: 'uppercase', color: 'var(--text-primary)', margin: '0 0 0.4rem' }}>
          <Cpu size={22} color="var(--accent-primary)" />
          Strategy_Engine_<span style={{ color: 'var(--accent-primary)' }}>v2.5</span>
        </h1>
        <p style={{ fontSize: '0.58rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.28em', margin: 0 }}>
          Active Node: Agentic_RAG_Cluster // Corpus: NSE_BSE_2026
        </p>
      </div>

      {/* ── Input ── */}
      <form onSubmit={handleGenerate} style={{ position: 'relative' }}>
        <input
          placeholder="DESCRIBE_GOAL: e.g., Aggressive growth in Indian EV sector for 3 years..."
          value={query}
          onChange={e => setQuery(e.target.value)}
          disabled={loading}
          style={{
            width: '100%',
            boxSizing: 'border-box',
            padding: '1.25rem 10rem 1.25rem 1.25rem',
            borderRadius: '14px',
            border: '1px solid var(--input-border)',
            background: 'var(--input-bg)',
            color: 'var(--text-primary)',
            fontFamily: 'monospace',
            fontSize: '0.8rem',
            outline: 'none',
            transition: 'border-color 0.25s ease, box-shadow 0.25s ease',
            WebkitBoxShadow: `0 0 0px 1000px ${INPUT_BG} inset`,
            caretColor: 'var(--accent-primary)',
          }}
          onFocus={e => { e.target.style.borderColor = 'var(--accent-primary)'; e.target.style.boxShadow = '0 0 14px var(--accent-glow)'; }}
          onBlur={e => { e.target.style.borderColor = 'var(--input-border)'; e.target.style.boxShadow = 'none'; }}
        />
        <button type="submit" disabled={loading || !query.trim()} className="cyber-btn" style={{ position: 'absolute', right: '0.6rem', top: '50%', transform: 'translateY(-50%)', width: 'auto', padding: '0.55rem 1.25rem', fontSize: '0.6rem' }}>
          {loading ? 'PROCESSING...' : 'INITIALIZE'}
        </button>
      </form>

      {/* ── Loading ── */}
      {loading && (
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '5rem 0', gap: '1.25rem' }}>
          <div style={{ position: 'relative', width: '56px', height: '56px' }}>
            <div style={{ width: '56px', height: '56px', border: '2px solid var(--surface-border)', borderTopColor: 'var(--accent-primary)', borderRadius: '50%', animation: 'genSpin 0.9s linear infinite' }} />
            <Zap size={18} color="var(--accent-primary)" style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', animation: 'genPulse 1s ease-in-out infinite' }} />
          </div>
          <div style={{ textAlign: 'center' }}>
            <p style={{ fontSize: '0.6rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.4em', color: 'var(--accent-primary)', margin: '0 0 0.4rem', animation: 'genPulse 1.5s ease-in-out infinite' }}>
              Synthesizing_Agentic_Debate
            </p>
            <p style={{ fontSize: '0.55rem', fontFamily: 'monospace', color: 'var(--text-muted)', margin: 0 }}>
              CROSS_REFERENCING_STOCKS_JSON + YFINANCE_ANALYTICS
            </p>
          </div>
        </div>
      )}

      {/* ── Result Dashboard ── */}
      {result && !loading && (
        <div ref={resultRef} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', opacity: visible ? 1 : 0, transform: visible ? 'translateY(0)' : 'translateY(16px)', transition: 'opacity 0.5s ease, transform 0.5s ease' }}>
          
          {/* Top Banner */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.85rem 1.1rem', borderRadius: '14px', background: 'var(--accent-muted)', border: '1px solid var(--accent-primary)', flexWrap: 'wrap', gap: '0.75rem' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
              <ShieldCheck size={16} color="var(--accent-primary)" />
              <span style={{ fontSize: '0.6rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.18em', color: 'var(--accent-primary)' }}>
                Identity_Verified_//_Strategy_Audited
              </span>
            </div>
            <button onClick={handleDownloadPDF} className="action-btn-small">
              <Download size={13} /> Export_Report
            </button>
          </div>

          {/* ── NEW: Fintech Metrics Grid ── */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1rem' }}>
            <MetricCard title="1Y_BACKTEST_VALIDATION" value={`${result.analytics?.backtest_1y || 0}%`} icon={<BarChart3 size={14}/>} color="var(--accent-primary)" />
            <MetricCard 
                title="BLACK_SWAN_DRAWDOWN" 
                value={`${result.analytics?.stress_test?.drawdown || 0}%`} 
                icon={<AlertTriangle size={14}/>} 
                color="#ef4444" 
                subtitle={`Event: ${result.analytics?.stress_test?.event}`} 
            />
            <MetricCard title="RISK_AUDIT_SCORE" value={`${result.analytics?.risk_score || 0}/100`} icon={<Activity size={14}/>} color="#3b82f6" />
          </div>

          {/* Main Content */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1rem' }}>
            <ResultBlock title="01_Market_Thesis" style={{ gridColumn: '1 / -1' }}>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', lineHeight: 1.7, fontStyle: 'italic', margin: 0, paddingLeft: '1rem', borderLeft: '2px solid var(--accent-primary)' }}>
                {result.summary}
              </p>
            </ResultBlock>

            <ResultBlock title="02_Asset_Allocations" style={{ gridColumn: 'span 1' }}>
              <MarkdownContent>{result.holdings}</MarkdownContent>
            </ResultBlock>

            <ResultBlock title="03_Agentic_Rationale" style={{ gridColumn: 'span 2' }}>
              <MarkdownContent>{result.rationale}</MarkdownContent>
            </ResultBlock>
          </div>
        </div>
      )}

      <style>{`
        @keyframes genSpin  { to { transform: rotate(360deg); } }
        @keyframes genPulse { 0%,100% { opacity:1; } 50% { opacity:0.4; } }
        .action-btn-small {
            display: flex; align-items: center; gap: 0.5rem; fontSize: 0.6rem; fontWeight: 700;
            text-transform: uppercase; letter-spacing: 0.15em; color: var(--accent-primary);
            background: transparent; border: 1px solid var(--accent-primary);
            border-radius: 8px; padding: 0.4rem 0.9rem; cursor: pointer; transition: all 0.25s ease;
        }
        .action-btn-small:hover { background: var(--accent-primary); color: #000; }
      `}</style>
    </div>
  );
};

const MetricCard = ({ title, value, icon, color, subtitle }) => (
  <div style={{ padding: '1.25rem', borderRadius: '18px', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', backdropFilter: 'blur(12px)' }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
      {React.cloneElement(icon, { color })}
      <span style={{ fontSize: '0.55rem', fontWeight: 700, letterSpacing: '0.15em', color: 'var(--text-muted)', textTransform: 'uppercase' }}>{title}</span>
    </div>
    <div style={{ fontSize: '1.5rem', fontWeight: 800, color: color }}>{value}</div>
    {subtitle && <div style={{ fontSize: '0.5rem', color: 'var(--text-muted)', marginTop: '0.2rem', textTransform: 'uppercase' }}>{subtitle}</div>}
  </div>
);

const ResultBlock = ({ title, children, style = {} }) => (
  <div style={{ padding: '1.5rem', borderRadius: '18px', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', backdropFilter: 'blur(12px)', ...style }}>
    <h3 style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.6rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.2em', color: 'var(--accent-primary)', margin: '0 0 1rem' }}>
      <Terminal size={12} color="var(--accent-primary)" />
      {title}
    </h3>
    {children}
  </div>
);

const MarkdownContent = ({ children }) => (
  <div className="md-content" style={{ fontSize: '0.82rem', lineHeight: 1.7, color: 'var(--text-secondary)' }}>
    <ReactMarkdown>{children}</ReactMarkdown>
  </div>
);

export default GeneratePage;
